class Solution {
public:
    int rob(vector<int>& nums) {
        int dp[n+1];
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            dp[i] = max(nums[i-1], dp[i-1]);
        }
        return dp[n];
    }
};

